/**
 * Writes packages/cre-jobs/secrets.yaml — CRE TS expects secrets at PROJECT ROOT, not inside the workflow dir.
 * Workflow workflow.yaml (local-simulation) uses secrets-path: ../secrets.yaml
 *
 * WASM only calls getSecret("GEMINI_API_KEY"); do not declare PRIVATE_KEY here (signing uses CRE_ETH_PRIVATE_KEY).
 */
"use strict";

const fs = require("fs");
const path = require("path");

function writeSecretsActive(jobRoot) {
  const creProjectRoot = path.resolve(jobRoot, "..");
  const lines = [
    "# Generated by secrets-active-manifest / simulate-resolve — gitignored at repo level",
    "secretsNames:",
    "  GEMINI_API_KEY:",
    "    - GEMINI_API_KEY",
  ];
  fs.writeFileSync(path.join(creProjectRoot, "secrets.yaml"), lines.join("\n") + "\n", "utf8");
}

const jobRoot = path.resolve(__dirname, "..");

module.exports = { writeSecretsActive };

if (require.main === module) {
  writeSecretsActive(jobRoot);
}
